<?php $this->extend('layouts.admin'); ?><?php $this->section('content'); ?><h1>Trailer listings</h1><form method="get" action="<?= e(url('admin/trailer-listings')) ?>"><label for="status">Status</label><select id="status" name="status"><option value="">All</option><?php foreach(['pending','active','sold','suspended','archived'] as $s): ?><option value="<?= $s ?>" <?= $status===$s?'selected':'' ?>><?= ucfirst($s) ?></option><?php endforeach; ?></select><button class="btn btn-secondary" type="submit">Filter</button></form><div class="table-wrap"><table class="data"><thead><tr><th>Listing</th><th>Business</th><th>Type</th><th>Status</th><th>Moderate</th></tr></thead><tbody><?php foreach($rows as $row): ?><tr><td><?= $this->e($row['title']) ?></td><td><?= $this->e($row['business_name']) ?></td><td><?= $this->e($row['trailer_type']) ?></td><td><?= $this->e($row['status']) ?></td><td><form method="post" action="<?= e(url('admin/trailer-listings/status')) ?>"><?= csrf_field() ?><input type="hidden" name="id" value="<?= (int)$row['id'] ?>"><select name="status"><?php foreach(['pending','active','sold','suspended','archived'] as $s): ?><option value="<?= $s ?>" <?= $row['status']===$s?'selected':'' ?>><?= ucfirst($s) ?></option><?php endforeach; ?></select><button class="btn btn-secondary" type="submit">Update</button></form></td></tr><?php endforeach; ?></tbody></table></div><?php $this->endSection(); ?>
